.darma-loader-loaders-css-29 {
      position: relative;
      display: inline-block;
      width: 57px;
      height: 57px;
      border-radius: 50%;
      border: 1px solid color-mix(in srgb, var(--loader-color, #22c55e) 24%, transparent);
    }
    .darma-loader-loaders-css-29 i {
      position: absolute;
      inset: -3px;
      border-radius: 50%;
      animation: darma-loader-loaders-css-29-orbit 1.22s linear infinite;
    }
    .darma-loader-loaders-css-29 i::before {
      content: "";
      position: absolute;
      top: 0;
      left: 50%;
      width: 10px;
      height: 10px;
      margin-left: -5px;
      border-radius: 50%;
      background: var(--loader-color, #22c55e);
      box-shadow: 0 0 18px color-mix(in srgb, var(--loader-color, #22c55e) 45%, transparent);
    }
    .darma-loader-loaders-css-29 i:nth-child(1) { animation-delay: 0.00s; }
.darma-loader-loaders-css-29 i:nth-child(2) { animation-delay: -0.41s; }
.darma-loader-loaders-css-29 i:nth-child(3) { animation-delay: -0.81s; }
    @keyframes darma-loader-loaders-css-29-orbit { to { transform: rotate(360deg); } }

